import java.util.Arrays;
import java.util.HashMap;
import java.util.HashSet;

class Solution {
    public static boolean solve(String x) {
        String[] parts = x.split(",");
        if (parts.length != 2) return false;
        String s = parts[0], t = parts[1];
        if (s.length() != t.length()) return false;
        HashMap<Character, Character> mapS2T = new HashMap<>();
        HashMap<Character, Character> mapT2S = new HashMap<>();
        for (int i = 0; i < s.length(); i++) {
            char c1 = s.charAt(i), c2 = t.charAt(i);
            if ((mapS2T.containsKey(c1) && mapS2T.get(c1) != c2) ||
                (mapT2S.containsKey(c2) && mapT2S.get(c2) != c1)) {
                return false;
            }
            mapS2T.put(c1, c2);
            mapT2S.put(c2, c1);
        }
        return true;
    }
}
